function emptyData(){ return { settings:{}, dashboard:null, residents:[], users:[], employees:[], shifts:[], messages:[], packages:[], visitors:[], invoices:[], notices:[], reservations:[], finance:[], boletos:[], commonAreas:[], incidents:[], maintenance:[], emergencyTypes:[], emergencyRequests:[], registrationRequests:[], notifications:[], audit:[], weather:null, systemUpdates:[], manuals:[], notifyConfig:null }; }
async function request(path, opts={}){
  const token = localStorage.getItem('vr_token');
  const headers = opts.raw ? (opts.headers || {}) : { 'Content-Type':'application/json', ...(opts.headers || {}) };
  const res = await fetch(API + path, { ...opts, headers:{ ...headers, ...(token ? { Authorization:'Bearer '+token } : {}) } });
  if(opts.blob) { if(!res.ok) throw new Error(await res.text()); return res.blob(); }
  const data = await res.json().catch(() => ({}));
  if(!res.ok) throw new Error(data.error || data.message || 'Erro na operação');
  return data;
}
const post = (path, body) => request(path, { method:'POST', body:JSON.stringify(body) });
const put = (path, body) => request(path, { method:'PUT', body:JSON.stringify(body) });
const del = (path) => request(path, { method:'DELETE' });

const routeDefaults = { portaria:'encomendas', cadastros:'moradores', financeiro:'movimentos', comunicacao:'notificacoes', central:'apps', configuracoes:'aparencia' };
const routeAliases = {
  encomendas:['portaria','encomendas'], visitantes:['portaria','visitantes'], escalas:['portaria','escalas'], mensagens:['portaria','mensagens'], portaria:['portaria','encomendas'],
  boletos:['financeiro','boletos'], movimentos:['financeiro','movimentos'], financeiro:['financeiro','movimentos'],
  moradores:['cadastros','moradores'], usuarios:['cadastros','usuarios'], solicitacoes:['cadastros','solicitacoes'], cadastros:['cadastros','moradores'],
  notificacoes:['comunicacao','notificacoes'], comunicados:['comunicacao','comunicados'], testes:['comunicacao','testes'], comunicacao:['comunicacao','notificacoes'],
  apps:['central','apps'], updates:['central','updates'], manuais:['central','manuais'], central:['central','apps'],
  aparencia:['configuracoes','aparencia'], menu:['configuracoes','menu'], notificacao:['configuracoes','notificacoes'], telegram:['configuracoes','telegram'], whatsapp:['configuracoes','whatsapp'], email:['configuracoes','email'], banco:['configuracoes','banco'], auditoria:['configuracoes','auditoria'], configuracoes:['configuracoes','aparencia']
};
function routeState(raw='dashboard', explicitSub){
  const cleanRoute = String(raw || 'dashboard').replace(/^#?\/?/, '').replace(/^\//, '');
  const [first, second] = cleanRoute.split('/').filter(Boolean);
  const key = first || 'dashboard';
  if(routeAliases[key]){
    const [active, aliasSub] = routeAliases[key];
    return { active, sub: explicitSub || second || aliasSub || routeDefaults[active] };
  }
  return { active:key, sub: explicitSub || second || routeDefaults[key] };
}
function routeHash(active, sub){
  return '/' + active + (sub && routeDefaults[active] ? '/' + sub : '');
}

function App(){
  const [session,setSession] = useState(() => JSON.parse(localStorage.getItem('vr_user') || 'null'));
  const [forms,setForms] = useState(initialForms());
  const [data,setData] = useState(emptyData());
  const initialRoute = routeState(location.hash || 'dashboard');
  const [active,setActive] = useState(initialRoute.active);
  const [sub,setSub] = useState(initialRoute.sub || 'encomendas');
  const [configTab,setConfigTab] = useState('aparencia');
  const [loginMode,setLoginMode] = useState('login');
  const [menuOpen,setMenuOpen] = useState(false);
  const [menuClosed,setMenuClosed] = useState(false);
  const [showPass,setShowPass] = useState(false);
  const [toast,setToast] = useState('');
  const [err,setErr] = useState('');
  const [confirm,setConfirm] = useState(null);
  const [reading,setReading] = useState('');
  const [lookup,setLookup] = useState({});
  const settings = { ...data.settings, ...Object.fromEntries(Object.entries(forms.settings || {}).filter(([,v]) => v !== '' && v !== undefined && v !== null)) };
  const isBruno = ['master','admin'].includes(session?.role);
  const can = (perm) => isBruno || session?.role === 'sindico' || Boolean(session?.permissions?.[perm]);

  useEffect(() => {
    const accent = settings.THEME_ACCENT || '#126b5f';
    const accent2 = settings.THEME_ACCENT_2 || settings.THEME_SECONDARY || '#35b5a2';
    document.body.dataset.appearance = settings.APPEARANCE || 'light';
    document.body.dataset.textsize = settings.THEME_TEXT_SIZE || settings.UI_DENSITY || 'comfort';
    document.documentElement.style.setProperty('--accent', accent);
    document.documentElement.style.setProperty('--accent2', accent2);
    document.querySelector('meta[name=theme-color]')?.setAttribute('content', accent);
  }, [settings.APPEARANCE, settings.UI_DENSITY, settings.THEME_TEXT_SIZE, settings.THEME_ACCENT, settings.THEME_ACCENT_2, settings.THEME_SECONDARY]);
  useEffect(() => { if(session) loadAll(); else request('/api/public-config').then(s => setData(d => ({ ...d, settings:s }))).catch(()=>null); }, [session]);
  useEffect(() => { const fn=()=>{ const r=routeState(location.hash || 'dashboard'); setActive(r.active); if(r.sub) setSub(r.sub); }; window.addEventListener('hashchange', fn); return()=>window.removeEventListener('hashchange', fn); }, []);

  function setForm(group, patch){ setForms(f => ({ ...f, [group]:{ ...f[group], ...patch } })); }
  function notify(message, fail=false){ setToast(message); if(fail) document.body.classList.add('shake'); setTimeout(()=>{ setToast(''); document.body.classList.remove('shake'); }, 3800); }
  async function safe(path, fallback){ try { return await request(path); } catch { return fallback; } }
  async function loadAll(){
    const [settingsRes,dashboard,residents,users,employees,shifts,messages,packagesRes,visitors,notices,reservations,finance,boletos,commonAreas,incidents,maintenance,emergencyTypes,emergencyRequests,registrationRequests,notifications,audit,weather,systemUpdates,manuals,notifyConfig] = await Promise.all([
      safe('/api/settings',{}), safe('/api/dashboard',null), safe('/api/residents',[]), safe('/api/users',[]), safe('/api/employees',[]), safe('/api/shifts',[]), safe('/api/messages',[]), safe('/api/packages',[]), safe('/api/visitors',[]), safe('/api/notices',[]), safe('/api/reservations',[]), safe('/api/finance',[]), safe('/api/boletos',[]), safe('/api/common-areas',[]), safe('/api/incidents',[]), safe('/api/maintenance',[]), safe('/api/emergency-types',[]), safe('/api/emergency-requests',[]), safe('/api/registration-requests',[]), safe('/api/notifications',[]), safe('/api/audit',[]), safe('/api/weather',null), safe('/api/system-updates',[]), safe('/api/manuals',[]), safe('/api/notify/config',null)
    ]);
    setData({ settings:settingsRes, dashboard, residents, users, employees, shifts, messages, packages:packagesRes, visitors, notices, reservations, finance, boletos, commonAreas, incidents, maintenance, emergencyTypes, emergencyRequests, registrationRequests, notifications, audit, weather, systemUpdates, manuals, notifyConfig });
    setForms(f => ({ ...f, settings:settingsRes }));
  }
  async function doLogin(e){ e.preventDefault(); setErr(''); try { const r=await post('/api/login', forms.login); localStorage.setItem('vr_token', r.token); localStorage.setItem('vr_user', JSON.stringify(r.user)); setSession(r.user); notify('Login realizado com segurança'); } catch(e){ setErr(e.message); } }
  function logout(){ localStorage.removeItem('vr_token'); localStorage.removeItem('vr_user'); setSession(null); setActive('dashboard'); }
  async function action(path, body, message, method='POST'){ try { method === 'PUT' ? await put(path, body) : await post(path, body); notify(message); await loadAll(); return true; } catch(e){ notify(e.message, true); return false; } }
  function openConfirm(title, fields, fn){ setConfirm({ title, fields, fn }); }
  async function confirmRun(){ const c=confirm; setConfirm(null); if(c?.fn) await c.fn(); }
  function go(tab, newSub){ const r=routeState(tab, newSub); setActive(r.active); if(r.sub) setSub(r.sub); location.hash=routeHash(r.active, r.sub); setMenuOpen(false); }
  async function lookupUnit(group, unit, maybeName=''){
    if(!unit) return null;
    try { const res = await request('/api/residents/lookup?unit='+encodeURIComponent(unit)+'&name='+encodeURIComponent(maybeName||'')); setLookup(l=>({ ...l, [group]:res })); const resident=res.primary || res.residents?.[0];
      if(resident){ if(group==='package') setForm('package',{ recipient:forms.package.recipient || resident.name }); if(group==='reservation') setForm('reservation',{ resident:forms.reservation.resident || resident.name, resident_id:resident.id }); }
      return res;
    } catch(e){ setLookup(l=>({ ...l, [group]:{ residents:[], message:e.message } })); return null; }
  }
  function prefillResidentFromContext(group){ const p = forms[group] || {}; setForm('resident', { ...forms.resident, name:p.recipient || p.resident || '', unit:p.unit || '', notes:p.extracted_text ? 'Criado a partir da leitura automática de encomenda.\n'+p.extracted_text.slice(0,500) : '' }); go('cadastros','moradores'); notify('Cadastro de morador pré-preenchido. Confira e salve.'); }
  async function readImage(file, type){ if(!file) return; setReading(type); try { const result = await Tesseract.recognize(file, 'eng'); const text = result?.data?.text || ''; const parsed = await post(type==='package' ? '/api/ocr/parse-package' : '/api/ocr/parse-invoice', { text }); if(type==='package'){ setForm('package', { ...forms.package, ...clean(parsed), extracted_text:text, label:text }); if(parsed.unit) await lookupUnit('package', parsed.unit, parsed.recipient); } else { setForm('invoice', { ...forms.invoice, ...clean(parsed), extracted_text:text }); } notify('Leitura automática concluída. Confira os dados antes de confirmar.'); } catch(e){ notify('Não consegui fazer a leitura automática: '+e.message, true); } finally { setReading(''); } }
  async function fileToData(file, cb){ if(!file) return; const reader = new FileReader(); reader.onload = () => cb(reader.result); reader.readAsDataURL(file); }

  if(!session) return <LoginPage forms={forms} setForm={setForm} mode={loginMode} setMode={setLoginMode} doLogin={doLogin} err={err} setShowPass={setShowPass} showPass={showPass} action={action} settings={settings} />;
  const menuItems = [ ['dashboard','Início',Home], ['portaria','Portaria',Package], ['reservas','Reservas',CalendarDays], ['financeiro','Financeiro',WalletCards], ['cadastros','Cadastros',Users], ['comunicacao','Comunicação',Bell], ['emergencia','Emergência',Siren], ['configuracoes','Configurações',Settings], ['central','Sistema e Apps',ShieldCheck] ];
  const shellClass = ['appShell', menuOpen?'mobile-open':'', menuClosed?'menu-closed':'', `menu-${settings.MENU_ORIENTATION||'vertical'}`].join(' ');
  const props = { data, forms, setForm, action, notify, loadAll, settings, session, can, openConfirm, lookup, lookupUnit, prefillResidentFromContext, readImage, reading, fileToData, setActive:go, sub, setSub, isBruno, configTab, setConfigTab, del, logout };
  return <div className={shellClass}>
    <button className="mobileMenu" onClick={()=>setMenuOpen(true)}><Menu /></button>{menuOpen && <div className="overlay" onClick={()=>setMenuOpen(false)} />}
    <aside><div className="brand brandCompact"><img src="/logo-vitoria-regia.svg" className="brandLogo"/><div className="brandText"><b>Vitória Régia</b><small>{VERSION}</small></div><button className="insideClose menuToggle" title={menuOpen ? 'Fechar menu' : (menuClosed?'Expandir menu':'Recolher menu')} onClick={()=>{ if(window.innerWidth < 861) setMenuOpen(false); else setMenuClosed(!menuClosed); }}>{window.innerWidth < 861 ? <X/> : (menuClosed ? <ChevronRight/> : <PanelLeft/>)}</button></div><nav>{menuItems.map(([key,label,Icon]) => <button key={key} className={active===key?'active':''} aria-current={active===key?'page':undefined} onClick={()=>go(key)}><Icon /><span>{label}</span></button>)}</nav><div className="sideBottom"><button onClick={()=>go('perfil')}><UserCheck/><span>Meu perfil</span></button><button onClick={logout}><LogOut/><span>Sair</span></button></div></aside>
    {can('emergency.use') && <button className="floatingEmergency" onClick={()=>go('emergencia')}><Siren/><span>Emergência</span></button>}
    <main className="content"><Topbar session={session} settings={settings}/>{toast && <div className="toast">{toast}</div>}
      {active==='dashboard' && <Dashboard {...props}/>} {active==='portaria' && <Portaria {...props}/>} {active==='reservas' && <Reservations {...props}/>} {active==='financeiro' && <Financeiro {...props}/>} {active==='cadastros' && <Cadastros {...props}/>} {active==='comunicacao' && <Comunicacao {...props}/>} {active==='emergencia' && <Emergency {...props}/>} {active==='configuracoes' && <SettingsPage {...props}/>} {active==='central' && <CentralPro {...props}/>} {active==='perfil' && <Profile {...props}/>} 
    </main><nav className="bottomNav"><button className={active==='dashboard'?'active':''} onClick={()=>go('dashboard')}><Home/><span>Início</span></button><button className={active==='reservas'?'active':''} onClick={()=>go('reservas')}><CalendarDays/><span>Reservas</span></button><button className={active==='comunicacao'?'active':''} onClick={()=>go('comunicacao','notificacoes')}><Bell/><span>Comunicados</span></button><button className={active==='perfil'?'active':''} onClick={()=>go('perfil')}><UserCheck/><span>Perfil</span></button></nav>{confirm && <ConfirmModal confirm={confirm} onCancel={()=>setConfirm(null)} onConfirm={confirmRun}/>}<Footer /></div>;
}
function LoginPage({ forms,setForm,mode,setMode,doLogin,err,setShowPass,showPass,action,settings }){ const channels=enabledChannels(settings); return <div className="loginPage buildingLogin redesignedLogin"><section className="loginPhoto"><div className="secureNote"><ShieldCheck/><div><b>Acesso seguro e inteligente.</b><small>Seu perfil é identificado automaticamente.</small></div></div></section><section className="loginCard premiumLoginCard"><img src="/logo-vitoria-regia.svg" className="loginLogo"/><small className="logoVersion">{VERSION}</small>{mode==='login' && <form onSubmit={doLogin}><h2>Bem-vindo de volta!</h2><p>Faça login para acessar o sistema.</p>{err && <p className="error">{err}</p>}<label>Usuário<input required placeholder="Usuário ou e-mail" value={forms.login.email} onChange={e=>setForm('login',{email:e.target.value})}/></label><label>Senha<div className="password"><input type={showPass?'text':'password'} placeholder="Senha" required value={forms.login.password} onChange={e=>setForm('login',{password:e.target.value})}/><button type="button" onClick={()=>setShowPass(v=>!v)}>{showPass?<EyeOff/>:<Eye/>}</button></div></label><button type="submit"><KeyRound/> Entrar</button><button type="button" className="textLink" onClick={()=>setMode('register')}>Ainda não é cadastrado?</button><button type="button" className="textLink subtle" onClick={()=>setMode('forgot')}>Esqueci minha senha</button></form>}{mode==='register' && <form onSubmit={e=>{e.preventDefault(); action('/api/register', forms.register, 'Solicitação enviada para aprovação');}}><h2>Solicitar cadastro</h2><p>Preencha seus dados. O síndico aprova o acesso antes da liberação.</p><label>Nome completo<input required value={forms.register.name} onChange={e=>setForm('register',{name:e.target.value})}/></label><label>Unidade<input required placeholder="Ex.: 101" value={forms.register.unit} onChange={e=>setForm('register',{unit:e.target.value})}/></label>{channels.email && <label>E-mail<input required={bool(settings.REGISTRATION_REQUIRE_EMAIL,true)} value={forms.register.email} onChange={e=>setForm('register',{email:e.target.value})}/></label>}{channels.whatsapp && <label>WhatsApp<input placeholder="DDD + número" value={forms.register.whatsapp_phone} onChange={e=>setForm('register',{whatsapp_phone:e.target.value})}/></label>}{channels.telegram && <label>Telegram<input placeholder="ID ou usuário Telegram" value={forms.register.telegram_chat_id} onChange={e=>setForm('register',{telegram_chat_id:e.target.value})}/></label>}<label>Documento<input value={forms.register.document} onChange={e=>setForm('register',{document:e.target.value})}/></label><button><UserPlus/> Enviar para aprovação</button><button type="button" className="textLink" onClick={()=>setMode('login')}>Voltar ao login</button></form>}{mode==='forgot' && <form onSubmit={e=>{e.preventDefault(); action('/api/forgot-password', forms.forgot, 'Se o usuário existir, a senha temporária será enviada');}}><h2>Recuperar senha</h2><p>Informe seu e-mail. A senha temporária será enviada somente para o usuário.</p><label>E-mail<input required value={forms.forgot.email} onChange={e=>setForm('forgot',{email:e.target.value})}/></label><button><Send/> Enviar senha temporária</button><button type="button" className="textLink" onClick={()=>setMode('login')}>Voltar ao login</button></form>}</section></div>; }
function Topbar({session,settings}){ return <div className="topbar"><div><small>{settings.CONDO_NAME || 'Condomínio Vitória Régia'}</small><h1>Olá, {session.name || roleLabel(session.role)} <span>👋</span></h1></div><div className="topActions"><button className="notificationBell"><Bell/><em>3</em></button><span className="badge profileBadge"><UserCheck/> {roleLabel(session.role)}<small>Perfil ativo</small></span></div></div>; }
function Dashboard({data,setActive,settings,session}){ const m=data.dashboard?.metrics || {}; const modules=[
  {key:'financeiro',sub:'movimentos',label:'Financeiro',desc:'Contas, taxas e relatórios',Icon:WalletCards},
  {key:'reservas',label:'Reservas',desc:'Áreas comuns e agendamentos',Icon:CalendarDays},
  {key:'portaria',sub:'visitantes',label:'Visitantes',desc:'Autorizações e histórico',Icon:Users},
  {key:'portaria',sub:'encomendas',label:'Encomendas',desc:'Gestão de entregas e recebimentos',Icon:Package},
  {key:'comunicacao',sub:'notificacoes',label:'Comunicados',desc:'Avisos e informativos',Icon:Bell},
  {key:'portaria',label:'Portaria',desc:'Controle de acesso e ocorrências',Icon:ShieldCheck},
  {key:'configuracoes',sub:'automacoes',label:'Automações',desc:'Regras e automatizações',Icon:Zap},
  {key:'central',sub:'manuais',label:'Ajuda',desc:'Manuais e atendimento',Icon:Info},
  {key:'configuracoes',label:'Configurações',desc:'Sistema e preferências',Icon:Settings},
  {key:'central',label:'Central Premium',desc:'Serviços exclusivos para seu condomínio',Icon:BadgeDollarSign,premium:true}
]; const metricItems=[{icon:<Users/>,label:'Moradores',value:m.residents||0,tab:'cadastros',sub:'moradores'},{icon:<Package/>,label:'Encomendas',value:m.pendingPackages||0,tab:'portaria',sub:'encomendas'},{icon:<CalendarDays/>,label:'Reservas',value:m.reservationsPending||0,tab:'reservas'},{icon:<UserCheck/>,label:'Visitantes hoje',value:m.visitorsToday||0,tab:'portaria',sub:'visitantes'},{icon:<Bell/>,label:'Mensagens',value:m.messagesNew||0,tab:'comunicacao',sub:'notificacoes'},{icon:<BadgeDollarSign/>,label:'Boletos',value:m.boletosPending||0,tab:'financeiro',sub:'boletos'}]; return <div className="dashboardRedesign"><section className="dashboardHero"><div><span className="eyebrow">Residencial Vitória Régia</span><h2>Bem-vindo ao Condomínio Vitória Régia</h2><p>{session?.role==='morador'?'Você visualiza as informações da sua unidade.':'Bloco único, 11 andares e 33 unidades cadastráveis de 101 a 1103.'}</p></div><div className="weather"><CloudSun/><div><b>{data.weather?.temperature ?? '--'}°C</b><small>{data.weather?.city || settings.WEATHER_CITY || 'João Pessoa'} · servidor</small></div></div></section><div className="moduleGrid">{modules.map(({key,sub,label,desc,Icon,premium})=><button key={label} type="button" className={premium?'moduleCard premium':'moduleCard'} onClick={()=>setActive(key,sub)}><span><Icon/></span><b>{label}</b><small>{desc}</small><ChevronRight/></button>)}</div><section className="permissionsCard"><div><h3><ShieldCheck/> Gerenciar perfis e permissões</h3><p>Controle quem acessa o sistema e o que cada um pode fazer.</p><ul><li>Síndicos podem ser moradores ou usuários terceirizados</li><li>Permissões personalizadas por função</li><li>Reatribuição de síndico de forma simples e segura</li><li>Histórico completo de alterações</li></ul></div><div className="permissionVisual"><Users/><ShieldCheck/><button onClick={()=>setActive('cadastros','usuarios')}>Gerenciar agora</button></div></section><section className="appsShowcase"><div><h3>Baixar aplicativos</h3><p>Acesse o sistema de onde estiver com nossos aplicativos oficiais.</p></div><div className="quickAppCards"><button onClick={()=>setActive('central','apps')}><Smartphone/><b>App do Morador</b><small>Tudo na palma da mão.</small></button><button onClick={()=>setActive('central','apps')}><UserCheck/><b>App do Síndico</b><small>Gestão completa.</small></button><button onClick={()=>setActive('central','apps')}><ShieldCheck/><b>App da Portaria (APK)</b><small>Controle de acesso.</small></button></div></section><div className="metricStrip aligned dashboardMetrics">{metricItems.map(item=><Metric key={item.label} {...item} onClick={()=>setActive(item.tab,item.sub)} />)}</div></div>; }
function Portaria(props){ return <Panel title="Portaria" subtitle="Encomendas, visitantes, reservas e atendimento rápido." icon={<Package/>}><SubTabs value={props.sub} setValue={props.setSub} tabs={[['encomendas','Encomendas'],['visitantes','Visitantes'],['escalas','Escalas'],['mensagens','Mensagens']]} />{props.sub==='encomendas'&&<Packages {...props}/>} {props.sub==='visitantes'&&<Visitors {...props}/>} {props.sub==='escalas'&&<Shifts {...props}/>} {props.sub==='mensagens'&&<Messages {...props}/>}</Panel>; }
function UnitLookupBox({result,onRegister}){ if(!result) return null; const arr=result.residents || []; return <div className={arr.length?'noticeBox ok':'noticeBox warn'}>{arr.length ? <><b>Morador encontrado</b><small>{arr.map(r=>`${r.name} · ${r.email || r.whatsapp_phone || r.phone || 'sem contato'}`).join(' | ')}</small></> : <><b>Nenhum morador cadastrado nesta unidade.</b><small>Recomende o cadastro antes de confirmar, principalmente para notificação automática.</small>{onRegister && <button type="button" className="buttonlike secondary" onClick={onRegister}><UserPlus/> Abrir cadastro pré-preenchido</button>}</>}</div>; }
function Packages({forms,setForm,action,openConfirm,lookup,lookupUnit,prefillResidentFromContext,readImage,reading,data,del,loadAll}){ const f=forms.package; const summary={Código:f.tracking, Destinatário:f.recipient, Unidade:f.unit, 'Canais':Object.entries(f.notification_channels||{}).filter(([,v])=>v).map(([k])=>channelNames[k]||k).join(', ')}; return <div className="stack"><form className="formGrid" onSubmit={e=>{e.preventDefault(); openConfirm('Confirmar cadastro de encomenda', summary, ()=>action('/api/packages', f, 'Encomenda cadastrada e morador notificado'));}}><label>Código/rastreio *<input required value={f.tracking} onChange={e=>setForm('package',{tracking:e.target.value})}/></label><label>Unidade *<div className="inline"><input required value={f.unit} onChange={e=>setForm('package',{unit:e.target.value})} onBlur={()=>lookupUnit('package', f.unit, f.recipient)}/><button type="button" onClick={()=>lookupUnit('package', f.unit, f.recipient)}><Search/></button></div></label><label>Destinatário *<input required value={f.recipient} onChange={e=>setForm('package',{recipient:e.target.value})}/></label><label>Etiqueta/observação<input value={f.label} onChange={e=>setForm('package',{label:e.target.value})}/></label><ChannelChooser settings={data.settings} value={f.notification_channels} onChange={v=>setForm('package',{notification_channels:v})}/><label className="fileButton"><ScanLine/> {reading==='package'?'Lendo etiqueta...':'Leitura automática da etiqueta'}<input type="file" accept="image/*" capture="environment" onChange={e=>readImage(e.target.files?.[0],'package')}/></label><textarea placeholder="Texto lido automaticamente / observações" value={f.extracted_text} onChange={e=>setForm('package',{extracted_text:e.target.value})}/><button><Plus/> Conferir e cadastrar</button></form><UnitLookupBox result={lookup.package} onRegister={()=>prefillResidentFromContext('package')}/><Table rows={data.packages} render={p=><><td><b>{p.tracking}</b><small>{p.recipient || p.resident_name} · Unidade {p.unit}</small></td><td><Code>{p.pickup_code || '-'}</Code></td><td><Status ok={p.status==='entregue'}>{p.status}</Status><small>{deliveryPreferenceLabel(p.delivery_preference)}</small></td><td className="actions"><button onClick={()=>action(`/api/packages/${p.id}/preference`,{delivery_preference:'receber_elevador'},'Preferência registrada')}>Elevador</button><button onClick={()=>action(`/api/packages/${p.id}/preference`,{delivery_preference:'retirar_portaria'},'Preferência registrada')}>Buscar</button><button onClick={()=>action(`/api/packages/${p.id}/deliver`,{},'Entrega concluída')}>Entregar</button><button onClick={()=>openConfirm('Remover encomenda',{Código:p.tracking,Unidade:p.unit},()=>del(`/api/packages/${p.id}`).then(loadAll))}><Trash2/></button></td></>}/></div>; }
function Visitors({data,forms,setForm,action,fileToData,openConfirm,del,loadAll}){ const f=forms.visitor; const submit=()=>action('/api/visitors', f, 'Visitante cadastrado'); return <div className="stack"><form className="formGrid" onSubmit={e=>{e.preventDefault(); openConfirm('Confirmar visitante',{Nome:f.name,Unidade:f.unit,Documento:f.document},submit);}}><label>Nome *<input required value={f.name} onChange={e=>setForm('visitor',{name:e.target.value})}/></label><label>Unidade *<input required value={f.unit} onChange={e=>setForm('visitor',{unit:e.target.value})}/></label><label>Documento<input value={f.document} onChange={e=>setForm('visitor',{document:e.target.value})}/></label><label>Telefone<input value={f.phone} onChange={e=>setForm('visitor',{phone:e.target.value})}/></label><label>Placa<input value={f.plate} onChange={e=>setForm('visitor',{plate:e.target.value})}/></label><label className="check"><input type="checkbox" checked={f.recurring} onChange={e=>setForm('visitor',{recurring:e.target.checked})}/>Visitante recorrente</label><label className="check"><input type="checkbox" checked={f.announce_required} onChange={e=>setForm('visitor',{announce_required:e.target.checked})}/>Porteiro deve anunciar</label><label>Forma de anúncio<select value={f.announcement_channel} onChange={e=>setForm('visitor',{announcement_channel:e.target.value})}><option value="interfone">Interfone</option><option value="app">Notificação do sistema</option><option value="whatsapp">WhatsApp</option></select></label><label className="fileButton"><Camera/> Tirar foto<input type="file" accept="image/*" capture="environment" onChange={e=>fileToData(e.target.files?.[0], photo_data=>setForm('visitor',{photo_data}))}/></label><button><Plus/> Conferir e cadastrar</button></form><Table rows={data.visitors} render={v=><><td>{v.photo_data?<img src={v.photo_data} className="avatar"/>:<UserCheck/>}<b>{v.name}</b><small>Unidade {v.unit} · {v.document}</small></td><td>{v.recurring?'Recorrente':'Avulso'}<small>{v.announcement_channel}</small></td><td className="actions"><button onClick={()=>openConfirm('Remover visitante',{Nome:v.name,Unidade:v.unit},()=>del(`/api/visitors/${v.id}`).then(loadAll))}><Trash2/></button></td></>}/></div>; }
function Shifts({data,forms,setForm,action}){ const e=forms.employee||{}; return <div className="stack"><div className="split"><form className="formGrid" onSubmit={ev=>{ev.preventDefault(); action('/api/employees', forms.employee || {}, 'Funcionário cadastrado');}}><h3>Funcionário</h3><label>Nome *<input required value={e.name||''} onChange={ev=>setForm('employee',{...(forms.employee||{}),name:ev.target.value})}/></label><label>Função<select value={e.role||'portaria'} onChange={ev=>setForm('employee',{...(forms.employee||{}),role:ev.target.value})}><option value="portaria">Portaria</option><option value="manutencao">Manutenção</option><option value="zeladoria">Zeladoria</option></select></label><label>Telefone<input value={e.phone||''} onChange={ev=>setForm('employee',{...(forms.employee||{}),phone:ev.target.value})}/></label><label>E-mail<input value={e.email||''} onChange={ev=>setForm('employee',{...(forms.employee||{}),email:ev.target.value})}/></label><button><Plus/> Salvar funcionário</button></form><form className="formGrid" onSubmit={ev=>{ev.preventDefault(); action('/api/shifts', forms.shift || {}, 'Escala cadastrada');}}><h3>Escala</h3><label>Funcionário<select required value={forms.shift?.employee_id||''} onChange={ev=>setForm('shift',{...(forms.shift||{}),employee_id:ev.target.value})}><option value="">Selecione</option>{data.employees.map(x=><option value={x.id} key={x.id}>{x.name}</option>)}</select></label><label>Início<input required type="datetime-local" value={forms.shift?.starts_at||''} onChange={ev=>setForm('shift',{...(forms.shift||{}),starts_at:ev.target.value})}/></label><label>Fim<input required type="datetime-local" value={forms.shift?.ends_at||''} onChange={ev=>setForm('shift',{...(forms.shift||{}),ends_at:ev.target.value})}/></label><button><Plus/> Salvar escala</button></form></div><Table rows={data.shifts} render={s=><><td><b>{s.employee_name}</b><small>{s.role}</small></td><td>{new Date(s.starts_at).toLocaleString('pt-BR')}</td><td>{new Date(s.ends_at).toLocaleString('pt-BR')}</td><td><Status ok>{s.status}</Status></td></>}/></div>; }
function Messages({data,forms,setForm,action}){ return <div className="stack"><form className="formGrid" onSubmit={e=>{e.preventDefault(); action('/api/messages', forms.message, 'Mensagem enviada ao funcionário em serviço');}}><label>Unidade<input value={forms.message.unit} onChange={e=>setForm('message',{unit:e.target.value})}/></label><label>Assunto<input required value={forms.message.subject} onChange={e=>setForm('message',{subject:e.target.value})}/></label><textarea required placeholder="Mensagem" value={forms.message.body} onChange={e=>setForm('message',{body:e.target.value})}/><button><Send/> Enviar</button></form><Table rows={data.messages} render={m=><><td><b>{m.subject}</b><small>{m.body}</small></td><td>Unidade {m.unit}<small>{m.employee_name?'Responsável: '+m.employee_name:'Sem funcionário em serviço'}</small></td><td><Status ok={m.status==='respondida'}>{m.status}</Status></td><td className="actions"><button onClick={()=>{const response=prompt('Resposta ao morador'); if(response) action(`/api/messages/${m.id}/respond`,{response},'Resposta enviada');}}>Responder</button></td></>}/></div>; }
function Reservations(props){ const {data,forms,setForm,action,openConfirm,lookup,lookupUnit,prefillResidentFromContext,fileToData,del}=props; const f=forms.reservation; const areas=data.commonAreas.length?data.commonAreas:[]; const area=areas.find(a=>a.name===f.area); useEffect(()=>{ if(area) setForm('reservation',{ fee_amount:f.fee_amount || area.fee_amount || '', document_text:f.document_text || area.rules_document || '' }); },[f.area]); const summary={Espaço:f.area,Unidade:f.unit,Morador:f.resident,Data:f.reserved_for,Horário:`${f.start_time} às ${f.end_time}`,Taxa:money(f.fee_amount)}; return <Panel title="Reservas" subtitle="Calendário, cobrança, aceite das regras e convidados." icon={<CalendarDays/>}><form className="formGrid reservationForm" onSubmit={e=>{e.preventDefault(); openConfirm('Confirmar reserva de espaço', summary, ()=>action('/api/reservations', f, 'Reserva criada e morador notificado'));}}><label>Espaço *<select required value={f.area} onChange={e=>setForm('reservation',{area:e.target.value})}>{areas.map(a=><option key={a.id||a.name}>{a.name}</option>)}</select></label><label>Unidade *<div className="inline"><input required value={f.unit} onChange={e=>setForm('reservation',{unit:e.target.value})} onBlur={()=>lookupUnit('reservation',f.unit,f.resident)}/><button type="button" onClick={()=>lookupUnit('reservation',f.unit,f.resident)}><Search/></button></div></label><label>Morador *<input required value={f.resident} onChange={e=>setForm('reservation',{resident:e.target.value})}/></label><label>Data *<input required type="date" value={f.reserved_for} onChange={e=>setForm('reservation',{reserved_for:e.target.value})}/></label><label>Início *<input required type="time" value={f.start_time} onChange={e=>setForm('reservation',{start_time:e.target.value})}/></label><label>Fim *<input required type="time" value={f.end_time} onChange={e=>setForm('reservation',{end_time:e.target.value})}/></label><label>Taxa<input type="number" value={f.fee_amount} onChange={e=>setForm('reservation',{fee_amount:e.target.value})}/></label><div className="terms"><CheckSquare/><span>{f.document_text || 'Normas de uso do espaço.'}</span><label><input required type="checkbox" checked={f.terms_accepted} onChange={e=>setForm('reservation',{terms_accepted:e.target.checked})}/>Li e aceito as regras de utilização do espaço.</label></div><button><Plus/> Conferir e solicitar reserva</button></form><UnitLookupBox result={lookup.reservation} onRegister={()=>prefillResidentFromContext('reservation')}/><GuestManager {...props}/><Table rows={data.reservations} render={r=><><td><b>{r.area}</b><small>Unidade {r.unit} · {r.resident}</small></td><td>{date(r.reserved_for)}<small>{r.start_time} às {r.end_time}</small></td><td>{money(r.fee_amount)}<small>{r.digitable_line || r.payment_link || ''}</small></td><td><Status ok={r.status==='confirmada'}>{r.status}</Status></td><td className="actions"><button onClick={()=>downloadIcs(r.id)}>ICS</button><button onClick={()=>request(`/api/reservations/${r.id}/google`).then(x=>window.open(x.url,'_blank'))}>Google</button><button onClick={()=>action(`/api/reservations/${r.id}/status`,{status:'pendente_pagamento'},'Morador avisado')}>Pagamento</button><button onClick={()=>action(`/api/reservations/${r.id}/status`,{status:'pendente_aceite_regras'},'Morador avisado')}>Aceite</button><button onClick={()=>action(`/api/reservations/${r.id}/approve`,{},'Reserva confirmada')}>Confirmar</button><button onClick={()=>action(`/api/reservations/${r.id}/cancel`,{reason:'Cancelado pelo painel'},'Reserva cancelada')}>Cancelar</button><button onClick={()=>openConfirm('Remover reserva',{Espaço:r.area,Data:date(r.reserved_for)},()=>del(`/api/reservations/${r.id}`).then(()=>loadAll()))}><Trash2/></button></td></>}/></Panel>; }
async function downloadIcs(id){ const blob=await request(`/api/reservations/${id}/ics`,{blob:true}); const url=URL.createObjectURL(blob); const a=document.createElement('a'); a.href=url; a.download=`reserva-${id}.ics`; a.click(); URL.revokeObjectURL(url); }
function GuestManager({data,forms,setForm,action,fileToData}){ const current=forms.reservationGuest.reservation_id || data.reservations[0]?.id || ''; const guests=data.reservations.find(r=>String(r.id)===String(current))?.visitors || []; return <div className="subpanel guestManager"><h3><ClipboardList/> Convidados do evento</h3><div className="formGrid"><label>Reserva<select value={current} onChange={e=>{setForm('reservationGuest',{reservation_id:e.target.value}); setForm('reservationVisitors',{reservation_id:e.target.value});}}><option value="">Selecione</option>{data.reservations.map(r=><option key={r.id} value={r.id}>{r.area} · {date(r.reserved_for)} · unidade {r.unit}</option>)}</select></label><div className="noticeBox"><b>Convidados cadastrados</b><small>{guests.length} pessoas na lista desta reserva.</small></div></div><form className="formGrid" onSubmit={e=>{e.preventDefault(); if(!current) return alert('Selecione a reserva'); action(`/api/reservations/${current}/visitors`, { visitors:[forms.reservationGuest] }, 'Convidado adicionado');}}><label>Nome *<input required value={forms.reservationGuest.name} onChange={e=>setForm('reservationGuest',{name:e.target.value})}/></label><label>Documento *<input required value={forms.reservationGuest.document} onChange={e=>setForm('reservationGuest',{document:e.target.value})}/></label><label>Telefone<input value={forms.reservationGuest.phone} onChange={e=>setForm('reservationGuest',{phone:e.target.value})}/></label><label>Tipo<select value={forms.reservationGuest.visitor_type} onChange={e=>setForm('reservationGuest',{visitor_type:e.target.value})}><option value="convidado">Convidado</option><option value="buffet">Buffet</option><option value="decoracao">Decoração</option><option value="fornecedor">Fornecedor</option></select></label><label>Faixa<select value={forms.reservationGuest.age_group} onChange={e=>setForm('reservationGuest',{age_group:e.target.value})}><option value="adulto">Adulto</option><option value="crianca">Criança</option><option value="bebe">Bebê de colo</option></select></label><label className="fileButton"><Camera/> Foto<input type="file" accept="image/*" capture="environment" onChange={e=>fileToData(e.target.files?.[0], photo_data=>setForm('reservationGuest',{photo_data}))}/></label><button><Plus/> Adicionar convidado</button></form><div className="formGrid"><textarea placeholder="Importar lista: Nome; Documento; Telefone; Placa; adulto/crianca/bebe" value={forms.reservationVisitors.bulk} onChange={e=>setForm('reservationVisitors',{bulk:e.target.value})}/><button onClick={()=>current? action(`/api/reservations/${current}/visitors`,{bulk:forms.reservationVisitors.bulk},'Lista importada'):alert('Selecione a reserva')}>Importar lista</button></div></div>; }
function Financeiro(props){ return <Panel title="Financeiro" subtitle="Boletos, cobranças, taxas e acompanhamento por unidade." icon={<WalletCards/>}><SubTabs value={props.sub} setValue={props.setSub} tabs={[['movimentos','Movimentos'],['boletos','Boletos']]} />{props.sub==='boletos'?<Boletos {...props}/>:<Finance {...props}/>}</Panel>; }
function Finance({data,forms,setForm,action,openConfirm}){ const f=forms.finance; return <div><form className="formGrid" onSubmit={e=>{e.preventDefault(); openConfirm('Confirmar lançamento financeiro',{Título:f.title,Unidade:f.unit,Valor:money(f.amount),Vencimento:f.due_date},()=>action('/api/finance',f,'Lançamento financeiro salvo'));}}><label>Título *<input required value={f.title} onChange={e=>setForm('finance',{title:e.target.value})}/></label><label>Valor *<input required type="number" value={f.amount} onChange={e=>setForm('finance',{amount:e.target.value})}/></label><label>Unidade<input value={f.unit} onChange={e=>setForm('finance',{unit:e.target.value})}/></label><label>Vencimento<input type="date" value={f.due_date} onChange={e=>setForm('finance',{due_date:e.target.value})}/></label><button><Plus/> Conferir e lançar</button></form><Table rows={data.finance} render={f=><><td><b>{f.title}</b><small>{f.category} · Unidade {f.unit || '-'}</small></td><td>{money(f.amount)}<small>{date(f.due_date)}</small></td><td><Status ok={f.status==='pago'}>{f.status}</Status></td></>}/></div>; }
function Boletos({data,forms,setForm,action,settings,openConfirm}){ const f=forms.boleto; const provider=settings.BANK_PROVIDER||'manual'; return <div><div className="noticeBox"><b>Banco configurado: {provider==='manual'?'manual / qualquer banco':provider}</b><small>Para emissão bancária automática, configure a API em Configurações → Banco.</small></div><form className="formGrid" onSubmit={e=>{e.preventDefault(); openConfirm('Confirmar boleto',{Título:f.title,Unidade:f.unit,Valor:money(f.amount),Banco:f.bank_name},()=>action('/api/boletos',{...f,provider},'Boleto salvo'));}}><label>Título *<input required value={f.title} onChange={e=>setForm('boleto',{title:e.target.value})}/></label><label>Valor *<input required type="number" value={f.amount} onChange={e=>setForm('boleto',{amount:e.target.value})}/></label><label>Unidade<input value={f.unit} onChange={e=>setForm('boleto',{unit:e.target.value})}/></label><label>Banco<input value={f.bank_name} onChange={e=>setForm('boleto',{bank_name:e.target.value})}/></label><label>Linha digitável<input value={f.digitable_line} onChange={e=>setForm('boleto',{digitable_line:e.target.value})}/></label><label>Link/PDF<input value={f.payment_link} onChange={e=>setForm('boleto',{payment_link:e.target.value})}/></label><button><Banknote/> Conferir e salvar boleto</button></form><Table rows={data.boletos} render={b=><><td><b>{b.title}</b><small>Unidade {b.unit} · {b.bank_name || b.provider}</small></td><td>{money(b.amount)}<small>{date(b.due_date)}</small></td><td><Status ok={b.status==='pago'}>{b.status}</Status></td><td><Code>{b.digitable_line || b.payment_link || '-'}</Code></td></>}/></div>; }
function Cadastros(props){ return <Panel title="Cadastros" subtitle="Moradores, usuários e aprovações separados para evitar confusão." icon={<Users/>}><SubTabs value={props.sub} setValue={props.setSub} tabs={[['moradores','Moradores'],['usuarios','Usuários'],['solicitacoes','Aprovações']]} />{props.sub==='moradores'&&<Moradores {...props}/>} {props.sub==='usuarios'&&<Usuarios {...props}/>} {props.sub==='solicitacoes'&&<Solicitacoes {...props}/>}</Panel>; }
function Moradores({data,forms,setForm,action,openConfirm,settings,del,loadAll}){ const f=forms.resident; const criteria=defaultCriteria(settings); const summary={Nome:f.name,Unidade:f.unit,'E-mail':f.email,WhatsApp:f.whatsapp_phone,Telegram:f.telegram_chat_id}; return <div><form className="formGrid" onSubmit={e=>{e.preventDefault(); openConfirm(f.id?'Confirmar alteração de morador':'Confirmar cadastro de morador', summary, ()=>action(f.id?`/api/residents/${f.id}`:'/api/residents', f, f.id?'Morador atualizado':'Morador cadastrado', f.id?'PUT':'POST'));}}><label>Nome *<input required value={f.name} onChange={e=>setForm('resident',{name:e.target.value})}/></label><label>Unidade *<input required value={f.unit} onChange={e=>setForm('resident',{unit:e.target.value})}/></label><label>E-mail<input value={f.email} onChange={e=>setForm('resident',{email:e.target.value})}/></label><label>WhatsApp<input value={f.whatsapp_phone} onChange={e=>setForm('resident',{whatsapp_phone:e.target.value})}/></label><label>Telegram<input value={f.telegram_chat_id} onChange={e=>setForm('resident',{telegram_chat_id:e.target.value})}/></label><label>Documento<input value={f.document} onChange={e=>setForm('resident',{document:e.target.value})}/></label><label>Veículo<input value={f.vehicle} onChange={e=>setForm('resident',{vehicle:e.target.value})}/></label><div className="channels criteriaBox"><b>Características para filtros</b>{criteria.map(c=><label key={c.key}><input type="checkbox" checked={Boolean(f.resident_tags?.[c.key])} onChange={e=>setForm('resident',{resident_tags:{...(f.resident_tags||{}),[c.key]:e.target.checked}})}/>{c.label}</label>)}</div><ChannelChooser settings={settings} value={f.notification_preferences} onChange={v=>setForm('resident',{notification_preferences:v})}/><button><Save/> Conferir e salvar morador</button></form><Table rows={data.residents} render={r=><><td><b>{r.name}</b><small>Unidade {r.unit} · {r.email || r.whatsapp_phone || r.phone || 'sem contato'}</small></td><td>{criteria.filter(c=>parseJson(r.resident_tags,{})[c.key]).map(c=>c.label).join(', ')}</td><td className="actions"><button onClick={()=>setForm('resident',{...r,resident_tags:parseJson(r.resident_tags,{}),notification_preferences:parseJson(r.notification_preferences,{})})}><Edit3/> Editar</button><button onClick={()=>openConfirm('Remover morador',{Nome:r.name,Unidade:r.unit},()=>del(`/api/residents/${r.id}`).then(loadAll))}><Trash2/> Remover</button></td></>}/></div>; }
function Usuarios({data,forms,setForm,action,openConfirm,del,loadAll,session}){ const f=forms.user; return <div><form className="formGrid" onSubmit={e=>{e.preventDefault(); openConfirm(f.id?'Confirmar alteração de usuário':'Confirmar cadastro de usuário',{Nome:f.name,'E-mail':f.email,Perfil:roleLabel(f.role),Unidade:f.unit},()=>action(f.id?`/api/users/${f.id}`:'/api/users', f, f.id?'Usuário atualizado':'Usuário cadastrado', f.id?'PUT':'POST'));}}><label>Nome *<input required value={f.name} onChange={e=>setForm('user',{name:e.target.value})}/></label><label>E-mail/usuário<input value={f.email} onChange={e=>setForm('user',{email:e.target.value})}/></label><label>Perfil<select value={f.role} onChange={e=>setForm('user',{role:e.target.value,user_type:e.target.value})}><option value="morador">Morador</option><option value="portaria">Portaria</option><option value="funcionario">Funcionário</option><option value="financeiro">Financeiro</option><option value="sindico">Síndico</option>{['master','admin'].includes(session.role) && <option value="master">Bruno</option>}</select></label>{!['portaria','funcionario','financeiro'].includes(f.role) && <label>Unidade<input value={f.unit} onChange={e=>setForm('user',{unit:e.target.value})}/></label>}<label>Senha temporária<input type="password" value={f.password} onChange={e=>setForm('user',{password:e.target.value})}/></label><label>WhatsApp<input value={f.whatsapp_phone} onChange={e=>setForm('user',{whatsapp_phone:e.target.value})}/></label><label>Telegram<input value={f.telegram_chat_id} onChange={e=>setForm('user',{telegram_chat_id:e.target.value})}/></label><label className="check"><input type="checkbox" checked={f.active!==false} onChange={e=>setForm('user',{active:e.target.checked})}/>Usuário ativo</label><ChannelChooser settings={data.settings} value={f.notification_preferences} onChange={v=>setForm('user',{notification_preferences:v})}/><button><Save/> Conferir e salvar usuário</button></form><Table rows={data.users} render={u=><><td><b>{u.name}</b><small>{u.email} · {roleLabel(u.role)}</small></td><td>{u.unit || '-'}</td><td><Status ok={u.active}>{u.active?'ativo':'inativo'}</Status></td><td className="actions"><button onClick={()=>setForm('user',{...u,notification_preferences:parseJson(u.notification_preferences,{})})}><Edit3/> Editar</button><button onClick={()=>action(`/api/users/${u.id}/reset-password`,{},'Senha temporária enviada somente ao usuário')}>Reset senha</button><button onClick={()=>openConfirm('Remover usuário',{Nome:u.name,'E-mail':u.email},()=>del(`/api/users/${u.id}`).then(loadAll))}><Trash2/> Remover</button></td></>}/></div>; }
function Solicitacoes({data,action}){ return <Table rows={data.registrationRequests} render={r=><><td><b>{r.name}</b><small>{r.email || r.whatsapp_phone || r.phone || r.telegram_chat_id} · unidade {r.unit}</small></td><td><Status ok={r.status==='aprovada'}>{r.status}</Status></td><td className="actions"><button onClick={()=>action(`/api/registration-requests/${r.id}/approve`,{},'Cadastro aprovado')}>Aprovar</button><button onClick={()=>action(`/api/registration-requests/${r.id}/reject`,{note:'Dados não conferem'},'Cadastro rejeitado')}>Rejeitar</button></td></>}/>; }
function Comunicacao(props){ return <Panel title="Comunicação" subtitle="Comunicados, notificações e teste dos canais." icon={<Bell/>}><SubTabs value={props.sub} setValue={props.setSub} tabs={[['notificacoes','Notificações'],['comunicados','Comunicados'],['testes','Testes']]} />{props.sub==='comunicados'?<Notices {...props}/>:props.sub==='testes'?<NotifyTests {...props}/>:<Notifications {...props}/>}</Panel>; }
function Notifications({data,action}){ return <Table rows={data.notifications} render={n=><><td><b>{n.title}</b><small>{n.body}</small></td><td><Code>{channelNames[n.channel]||n.channel||'Sistema'}</Code></td><td><Status ok={n.status==='lida'}>{n.status}</Status><small>{date(n.created_at)}</small></td><td className="actions"><button onClick={()=>action(`/api/notifications/${n.id}/read`,{},'Notificação lida')}>Marcar lida</button></td></>}/>; }
function Notices({data,forms,setForm,action,settings,openConfirm}){ const criteria=defaultCriteria(settings); const f=forms.notice; return <div><form className="formGrid" onSubmit={e=>{e.preventDefault(); openConfirm('Confirmar comunicado',{Título:f.title,Público:f.target_role},()=>action('/api/notices', f, 'Comunicado enviado'));}}><label>Título *<input required value={f.title} onChange={e=>setForm('notice',{title:e.target.value})}/></label><label>Prioridade<select value={f.priority} onChange={e=>setForm('notice',{priority:e.target.value})}><option value="normal">Normal</option><option value="alta">Alta</option><option value="critica">Crítica</option></select></label><label>Público<select value={f.target_role} onChange={e=>setForm('notice',{target_role:e.target.value})}><option value="todos">Todos</option><option value="morador">Moradores</option><option value="portaria">Portaria</option></select></label><div className="channels criteriaBox"><b>Enviar somente para moradores com:</b>{criteria.map(c=><label key={c.key}><input type="checkbox" checked={Boolean(f.target_criteria?.[c.key])} onChange={e=>setForm('notice',{target_criteria:{...(f.target_criteria||{}),[c.key]:e.target.checked}})}/>{c.label}</label>)}</div><textarea required placeholder="Mensagem" value={f.body} onChange={e=>setForm('notice',{body:e.target.value})}/><button><Send/> Conferir e enviar</button></form><Table rows={data.notices} render={n=><><td><b>{n.title}</b><small>{n.body}</small></td><td>{n.priority}</td><td>{date(n.created_at)}</td></>}/></div>; }
function NotifyTests({forms,setForm,action,data}){ const f=forms.notifyTest; const presets=[['email','E-mail',Mail],['telegram','Telegram',MessageCircle],['whatsapp','WhatsApp',Smartphone],['browser','Navegador',BellRing]]; const configs=data.notifyConfig || {}; return <div className="split notifyTestSplit"><form className="formGrid" onSubmit={e=>{e.preventDefault(); action('/api/notify/test', f, 'Teste enviado/processado');}}><h3>Teste de mensagens do sistema</h3><div className="quickChannels">{presets.map(([k,l,Icon])=><button type="button" className={f.channel===k?'active':''} key={k} onClick={()=>setForm('notifyTest',{channel:k})}><Icon/> {l}</button>)}</div><label>Destino<input placeholder="e-mail, telefone ou chat ID" value={f.to} onChange={e=>setForm('notifyTest',{to:e.target.value})}/></label><label>Assunto<input value={f.subject} onChange={e=>setForm('notifyTest',{subject:e.target.value})}/></label><textarea value={f.message} onChange={e=>setForm('notifyTest',{message:e.target.value})}/><button><Send/> Enviar teste</button></form><SettingCard title="Configurações ativas" icon={<Activity/>}><div className="configList cleanConfig">{Object.entries(configs).length?Object.entries(configs).map(([k,v])=><span className="miniRow" key={k}>{k}<small>{typeof v==='object'?JSON.stringify(v):String(v)}</small></span>):<small>Carregue as configurações para ver o status dos canais.</small>}</div></SettingCard></div>; }
function EmergencyIcon({code,label}){ const key=String(code||label||'').toLowerCase(); if(key.includes('fogo')||key.includes('incend')) return <Flame/>; if(key.includes('invas')||key.includes('seguran')) return <ShieldAlert/>; if(key.includes('méd')||key.includes('medic')||key.includes('ambul')) return <Ambulance/>; if(key.includes('vaz')||key.includes('água')||key.includes('agua')) return <Droplets/>; if(key.includes('energia')||key.includes('elétr')) return <Zap/>; if(key.includes('elev')) return <Building2/>; if(key.includes('extint')) return <FireExtinguisher/>; return <CircleAlert/>; }
function Emergency({data,forms,setForm,action,openConfirm,settings}){ const types=data.emergencyTypes.length?data.emergencyTypes:[]; const f=forms.emergency; const selected=types.find(t=>t.code===f.type) || types[0]; return <Panel title="Emergência" subtitle="Solicitações passam pela portaria/síndico; somente fogo e invasão geram aviso geral." icon={<Siren/>}><div className="emergencyGrid realIcons">{types.map(t=><article className={'emergency '+(f.type===t.code?'selected':'')} key={t.code} onClick={()=>setForm('emergency',{type:t.code})}><span className="emergencyIcon"><EmergencyIcon code={t.code} label={t.label}/></span><h3>{t.label}</h3><p>{t.instructions}</p>{t.phone && <b className="emergencyPhone"><Phone/> {t.phone}</b>}</article>)}</div><form className="formGrid emergencyForm" onSubmit={e=>{e.preventDefault(); openConfirm('Confirmar solicitação de emergência',{Tipo:selected?.label||f.type,Unidade:f.unit||'Área comum'},()=>action('/api/emergency',f,'Emergência enviada para avaliação'));}}><label>Tipo<select value={f.type} onChange={e=>setForm('emergency',{type:e.target.value})}>{types.map(t=><option value={t.code} key={t.code}>{t.label}</option>)}</select></label><label>Unidade/local<input required value={f.unit} onChange={e=>setForm('emergency',{unit:e.target.value})} placeholder="Ex.: 803, elevador ou garagem"/></label><textarea placeholder="Descreva rapidamente o que está acontecendo" value={f.message} onChange={e=>setForm('emergency',{message:e.target.value})}/><div className="noticeBox warn"><b>Alerta crítico</b><small>Incêndio e invasão podem gerar notificação persistente e vibração forte quando o aparelho permitir. Outros tipos ficam restritos à equipe responsável.</small></div><button><Siren/> Enviar solicitação</button></form><Table rows={data.emergencyRequests} render={r=><><td><b>{r.type_label}</b><small>{r.unit} · {r.message}</small></td><td><Status ok={r.status==='aprovada'}>{r.status}</Status></td><td className="actions"><button className="confirmAction" onClick={()=>action(`/api/emergency-requests/${r.id}/approve`,{note:'Aprovado'},'Emergência aprovada')}>Aprovar</button><button className="dangerAction" onClick={()=>action(`/api/emergency-requests/${r.id}/reject`,{note:'Rejeitada'},'Emergência rejeitada')}>Rejeitar</button></td></>}/></Panel>; }
function Profile({forms,setForm,action,settings}){ const f=forms.profile; return <Panel title="Meu perfil" subtitle="Cada morador mantém seus contatos atualizados." icon={<UserCheck/>}><form className="formGrid" onSubmit={e=>{e.preventDefault(); action('/api/profile', f, 'Perfil atualizado', 'PUT');}}><label>Nome<input value={f.name} onChange={e=>setForm('profile',{name:e.target.value})}/></label><label>E-mail<input value={f.email} onChange={e=>setForm('profile',{email:e.target.value})}/></label><label>WhatsApp<input value={f.whatsapp_phone} onChange={e=>setForm('profile',{whatsapp_phone:e.target.value})}/></label><label>Telegram<input value={f.telegram_chat_id} onChange={e=>setForm('profile',{telegram_chat_id:e.target.value})}/></label><label>Unidade<input value={f.unit} onChange={e=>setForm('profile',{unit:e.target.value})}/></label><label>Nova senha<input type="password" value={f.password} onChange={e=>setForm('profile',{password:e.target.value})}/></label><ChannelChooser settings={settings} value={f.notification_preferences} onChange={v=>setForm('profile',{notification_preferences:v})}/><button><Save/> Salvar meu perfil</button></form></Panel>; }
function SettingsPage(props){ const tabs=[['aparencia','Aparência'],['notificacoes','Notificações'],['email','E-mail'],['telegram','Telegram'],['whatsapp','WhatsApp'],['banco','Banco'],['condominio','Condomínio'],['areas','Áreas'],['apps','Apps'],['atualizacoes','Atualizações'],['auditoria','Auditoria']]; return <Panel title="Configurações" subtitle="Tudo em subgrupos simples e objetivos." icon={<Settings/>}><SubTabs value={props.configTab} setValue={props.setConfigTab} tabs={tabs}/>{props.configTab==='aparencia'&&<AppearanceSettings {...props}/>} {props.configTab==='notificacoes'&&<NotificationSettings {...props}/>} {props.configTab==='email'&&<ProviderSettings {...props} type="email"/>} {props.configTab==='telegram'&&<ProviderSettings {...props} type="telegram"/>} {props.configTab==='whatsapp'&&<ProviderSettings {...props} type="whatsapp"/>} {props.configTab==='banco'&&<BankSettings {...props}/>} {props.configTab==='condominio'&&<CondoSettings {...props}/>} {props.configTab==='areas'&&<AreasSettings {...props}/>} {props.configTab==='apps'&&<AppsSettings {...props}/>} {props.configTab==='atualizacoes'&&<UpdateSettings {...props}/>} {props.configTab==='auditoria'&&<AuditPage {...props}/>}</Panel>; }
function saveSettings(forms, action){ const payload={...forms.settings}; for(const k of Object.keys(payload)){ if(sensitive.has(k) && (!payload[k] || String(payload[k]).includes('***'))) delete payload[k]; } return action('/api/settings', payload, 'Configurações salvas'); }
function AppearanceSettings({forms,setForm,action,settings}){ const s=forms.settings; return <SettingCard title="Aparência" icon={<Palette/>}><div className="themePreview"><img src="/logo-vitoria-regia.svg"/><div><b>Prévia do Vitória Régia</b><small>A cor muda ao selecionar; clique em salvar para manter para todos.</small></div></div><div className="formGrid"><label>Cor principal do sistema<input type="color" value={s.THEME_ACCENT || settings.THEME_ACCENT || '#126b5f'} onChange={e=>setForm('settings',{THEME_ACCENT:e.target.value})}/></label><label>Cor de apoio<input type="color" value={s.THEME_ACCENT_2 || settings.THEME_ACCENT_2 || '#35b5a2'} onChange={e=>setForm('settings',{THEME_ACCENT_2:e.target.value})}/></label><label>Modo<select value={s.APPEARANCE||settings.APPEARANCE||'light'} onChange={e=>setForm('settings',{APPEARANCE:e.target.value})}><option value="light">Claro</option><option value="dark">Escuro</option></select></label><label>Orientação do menu<select value={s.MENU_ORIENTATION||settings.MENU_ORIENTATION||'vertical'} onChange={e=>setForm('settings',{MENU_ORIENTATION:e.target.value})}><option value="vertical">Lateral</option><option value="top">Superior</option><option value="floating">Compacto</option></select></label><label>Tamanho do texto<select value={s.THEME_TEXT_SIZE||s.UI_DENSITY||settings.THEME_TEXT_SIZE||settings.UI_DENSITY||'comfort'} onChange={e=>setForm('settings',{THEME_TEXT_SIZE:e.target.value,UI_DENSITY:e.target.value})}><option value="compact">Menor</option><option value="comfort">Normal</option><option value="spacious">Maior</option></select></label><button onClick={()=>saveSettings(forms,action)}><Save/> Salvar aparência</button></div></SettingCard>; }
function NotificationSettings(props){ const {forms,setForm,action}=props; const s=forms.settings; return <div className="stack"><SettingCard title="Canais liberados" icon={<Bell/>}><div className="channels"><label><input type="checkbox" checked={bool(s.ENABLE_EMAIL,true)} onChange={e=>setForm('settings',{ENABLE_EMAIL:String(e.target.checked)})}/>E-mail</label><label><input type="checkbox" checked={bool(s.ENABLE_WHATSAPP,false)} onChange={e=>setForm('settings',{ENABLE_WHATSAPP:String(e.target.checked)})}/>WhatsApp</label><label><input type="checkbox" checked={bool(s.ENABLE_TELEGRAM,false)||bool(s.TELEGRAM_ENABLED,false)} onChange={e=>setForm('settings',{ENABLE_TELEGRAM:String(e.target.checked),TELEGRAM_ENABLED:String(e.target.checked)})}/>Telegram</label><label><input type="checkbox" checked={bool(s.ENABLE_BROWSER_PUSH,true)} onChange={e=>setForm('settings',{ENABLE_BROWSER_PUSH:String(e.target.checked)})}/>Navegador</label></div><button className="saveConfig" onClick={()=>saveSettings(forms,action)}><Save/> Salvar canais</button></SettingCard><NotifyTests {...props}/></div>; }
function ProviderSettings({forms,setForm,action,type,data}){ const s=forms.settings; const maps={email:[['MAIL_PROVIDER','Provedor principal'],['EMAIL_PROVIDER','Provedor de e-mail'],['SENDGRID_API_KEY','SendGrid API Key'],['SENDGRID_FROM_EMAIL','E-mail remetente'],['SENDGRID_FROM_NAME','Nome do remetente'],['SENDGRID_REPLY_TO','Responder para'],['SENDGRID_TO_DEFAULT','E-mail padrão de teste'],['MAIL_FROM','Remetente SMTP'],['SMTP_HOST','SMTP servidor'],['SMTP_PORT','SMTP porta'],['SMTP_USER','SMTP usuário'],['SMTP_PASS','SMTP senha'],['PUBLIC_APP_URL','URL pública do sistema']],telegram:[['TELEGRAM_ENABLED','Telegram ativo'],['ENABLE_TELEGRAM','Canal Telegram liberado'],['TELEGRAM_START_URL','Link de início do bot'],['TELEGRAM_BOT_USERNAME','Usuário do bot'],['TELEGRAM_BOT_TOKEN','Token do bot'],['TELEGRAM_CHAT_ID','Chat padrão'],['TELEGRAM_WEBHOOK_SECRET','Segredo do webhook'],['TELEGRAM_PARSE_MODE','Modo de texto'],['TELEGRAM_API_BASE_URL','Base da API']],whatsapp:[['ENABLE_WHATSAPP','Canal WhatsApp liberado'],['WHATSAPP_API_VERSION','Versão da API'],['WHATSAPP_API_BASE_URL','Base da API'],['WHATSAPP_PHONE_NUMBER_ID','Phone Number ID'],['WHATSAPP_BUSINESS_ACCOUNT_ID','Business Account ID'],['WHATSAPP_ACCESS_TOKEN','Token de acesso'],['WHATSAPP_API_TOKEN','Token alternativo'],['WHATSAPP_TEMPLATE_PACKAGE','Template de encomenda'],['WHATSAPP_TEMPLATE_RESERVATION','Template de reserva'],['WHATSAPP_TO_DEFAULT','WhatsApp padrão de teste']]}; const title=type==='email'?'E-mail / SendGrid / SMTP':type==='telegram'?'Telegram':'WhatsApp'; const icon=type==='email'?<Mail/>:type==='telegram'?<MessageCircle/>:<Smartphone/>; const isBool=(k)=>/^ENABLE_|_ENABLED$/.test(k) || ['TELEGRAM_ENABLED'].includes(k); const testPayload= type==='email'?{channel:'email',to:s.SENDGRID_TO_DEFAULT || data.notifyConfig?.email?.sendgridFromEmail || '',subject:'Teste Vitória Régia',message:'Teste de e-mail do Sistema Vitória Régia.'}: type==='telegram'?{channel:'telegram',to:s.TELEGRAM_CHAT_ID || '',message:'Teste do Telegram - Sistema Vitória Régia.'}:{channel:'whatsapp',to:s.WHATSAPP_TO_DEFAULT || '',message:'Teste de WhatsApp - Sistema Vitória Régia.'}; return <SettingCard title={title} icon={icon}><div className="noticeBox ok"><b>Variáveis de comunicação</b><small>Os campos abaixo substituem as variáveis do Render quando salvos no sistema. Tokens, senhas e chaves aparecem mascarados e nunca são enviados ao GitHub.</small></div><div className="formGrid providerGrid">{maps[type].map(([k,l])=> isBool(k) ? <label className="check" key={k}><input type="checkbox" checked={bool(s[k], false)} onChange={e=>setForm('settings',{[k]:String(e.target.checked), ...(k==='TELEGRAM_ENABLED'?{ENABLE_TELEGRAM:String(e.target.checked)}:{})})}/>{l}</label> : <label key={k}>{l}<input type={sensitive.has(k)?'password':'text'} placeholder={sensitive.has(k)?maskValue(s[k]):''} value={sensitive.has(k) && String(s[k]||'').includes('***')?'':(s[k]||'')} onChange={e=>setForm('settings',{[k]:e.target.value})}/></label>)}<button onClick={()=>saveSettings(forms,action)}><Save/> Salvar {title}</button><button type="button" className="secondaryAction" onClick={()=>action('/api/notify/test', testPayload, 'Teste enviado/processado') }><Send/> Testar {type==='email'?'e-mail':type==='telegram'?'Telegram':'WhatsApp'}</button>{type==='telegram'&&<><button type="button" className="secondaryAction" onClick={()=>action('/api/telegram/get-me',{},'Telegram testado') }><MessageCircle/> Verificar bot</button><button type="button" className="secondaryAction" onClick={()=>action('/api/telegram/set-webhook',{base_url:s.PUBLIC_APP_URL||window.location.origin},'Webhook configurado') }><RefreshCcw/> Configurar webhook</button><button type="button" className="secondaryAction" onClick={()=>action('/api/telegram/webhook-info',{},'Webhook verificado') }><Activity/> Ver webhook</button></>}</div><NotifyTests forms={forms} setForm={setForm} action={action} data={data}/></SettingCard>; }
function BankSettings({forms,setForm,action}){ const s=forms.settings; const keys=[['BANK_PROVIDER','Banco/gateway'],['BANK_API_BASE_URL','URL da API'],['BANK_CLIENT_ID','Client ID'],['BANK_CLIENT_SECRET','Client secret'],['BANK_API_TOKEN','Token API'],['BANK_ACCOUNT','Conta'],['BANK_AGENCY','Agência'],['BANK_WALLET','Carteira'],['BANK_CONTRACT','Convênio/contrato'],['BANK_PIX_KEY','Chave Pix']]; return <SettingCard title="Banco e boletos" icon={<Banknote/>}><div className="formGrid">{keys.map(([k,l])=><label key={k}>{l}<input type={sensitive.has(k)?'password':'text'} placeholder={sensitive.has(k)?maskValue(s[k]):''} value={sensitive.has(k) && String(s[k]||'').includes('***')?'':(s[k]||'')} onChange={e=>setForm('settings',{[k]:e.target.value})}/></label>)}<label className="check"><input type="checkbox" checked={bool(s.BOLETO_AUTO_GENERATE,false)} onChange={e=>setForm('settings',{BOLETO_AUTO_GENERATE:String(e.target.checked)})}/>Gerar boletos automaticamente quando houver API configurada</label><button onClick={()=>saveSettings(forms,action)}><Save/> Salvar banco</button></div></SettingCard>; }
function CondoSettings({forms,setForm,action}){ const s=forms.settings; return <SettingCard title="Condomínio" icon={<Building2/>}><div className="formGrid"><label>Nome<input value={s.CONDO_NAME||''} onChange={e=>setForm('settings',{CONDO_NAME:e.target.value})}/></label><label>Endereço<input value={s.CONDO_ADDRESS||''} onChange={e=>setForm('settings',{CONDO_ADDRESS:e.target.value})}/></label><label>Operadora do elevador<input value={s.ELEVATOR_OPERATOR_NAME||''} onChange={e=>setForm('settings',{ELEVATOR_OPERATOR_NAME:e.target.value})}/></label><label>Telefone emergência elevador<input value={s.ELEVATOR_EMERGENCY_PHONE||''} onChange={e=>setForm('settings',{ELEVATOR_EMERGENCY_PHONE:e.target.value})}/></label><label className="check"><input type="checkbox" checked={bool(s.ALLOW_MULTIPLE_RESIDENTS_PER_UNIT,false)} onChange={e=>setForm('settings',{ALLOW_MULTIPLE_RESIDENTS_PER_UNIT:String(e.target.checked)})}/>Permitir mais de um morador por unidade</label><button onClick={()=>saveSettings(forms,action)}><Save/> Salvar condomínio</button></div></SettingCard>; }
function AreasSettings({data,forms,setForm,action,openConfirm,del,loadAll}){ const f=forms.commonArea; return <div><SettingCard title="Áreas de lazer" icon={<CalendarDays/>}><form className="formGrid" onSubmit={e=>{e.preventDefault(); openConfirm('Confirmar área de lazer',{Nome:f.name,Taxa:money(f.fee_amount),Convidados:f.max_guests},()=>action('/api/common-areas',f,'Área de lazer salva'));}}><label>Nome *<input required value={f.name} onChange={e=>setForm('commonArea',{name:e.target.value})}/></label><label>Taxa<input type="number" value={f.fee_amount} onChange={e=>setForm('commonArea',{fee_amount:e.target.value})}/></label><label>Máximo de convidados<input type="number" value={f.max_guests} onChange={e=>setForm('commonArea',{max_guests:e.target.value})}/></label><label className="check"><input type="checkbox" checked={f.count_children!==false} onChange={e=>setForm('commonArea',{count_children:e.target.checked})}/>Crianças contam no limite</label><label className="check"><input type="checkbox" checked={f.count_infants===true} onChange={e=>setForm('commonArea',{count_infants:e.target.checked})}/>Bebês de colo contam no limite</label><textarea placeholder="Regras de uso" value={f.rules_document} onChange={e=>setForm('commonArea',{rules_document:e.target.value})}/><button><Save/> Salvar área</button></form></SettingCard><Table rows={data.commonAreas} render={a=><><td><b>{a.name}</b><small>{money(a.fee_amount)} · {a.max_guests} convidados</small></td><td className="actions"><button onClick={()=>setForm('commonArea',{...a})}>Editar</button><button onClick={()=>openConfirm('Remover área',{Nome:a.name},()=>del(`/api/common-areas/${a.id}`).then(loadAll))}><Trash2/></button></td></>}/></div>; }
function AppsSettings({forms,setForm,action}){ const s=forms.settings; return <SettingCard title="Aplicativos" icon={<AppWindow/>}><div className="channels"><label><input type="checkbox" checked={bool(s.ENABLE_APP_PORTARIA,true)} onChange={e=>setForm('settings',{ENABLE_APP_PORTARIA:String(e.target.checked)})}/>Portaria</label><label><input type="checkbox" checked={bool(s.ENABLE_APP_SINDICO,true)} onChange={e=>setForm('settings',{ENABLE_APP_SINDICO:String(e.target.checked)})}/>Síndico</label><label><input type="checkbox" checked={bool(s.ENABLE_APP_MORADOR,true)} onChange={e=>setForm('settings',{ENABLE_APP_MORADOR:String(e.target.checked)})}/>Morador</label></div><div className="formGrid"><label>URL APK Portaria<input value={s.APK_PORTARIA_URL||''} onChange={e=>setForm('settings',{APK_PORTARIA_URL:e.target.value})}/></label><label>URL APK Síndico<input value={s.APK_SINDICO_URL||''} onChange={e=>setForm('settings',{APK_SINDICO_URL:e.target.value})}/></label><label>URL APK Morador<input value={s.APK_MORADOR_URL||''} onChange={e=>setForm('settings',{APK_MORADOR_URL:e.target.value})}/></label><button onClick={()=>saveSettings(forms,action)}><Save/> Salvar apps</button></div></SettingCard>; }
function UpdateSettings({forms,setForm,action,settings,isBruno}){ return <SettingCard title="Atualizações" icon={<RefreshCcw/>}><div className="formGrid"><label className="check"><input type="checkbox" checked={bool(forms.settings.SHOW_UPDATES_TO_SINDICO,false)} onChange={e=>setForm('settings',{SHOW_UPDATES_TO_SINDICO:String(e.target.checked)})}/>Mostrar menu de atualização para o síndico</label><label>Canal<select value={forms.settings.UPDATE_CHANNEL||'stable'} onChange={e=>setForm('settings',{UPDATE_CHANNEL:e.target.value})}><option value="stable">Estável</option><option value="beta">Teste</option></select></label><label>Feed de atualização<input value={forms.settings.UPDATE_FEED_URL||''} onChange={e=>setForm('settings',{UPDATE_FEED_URL:e.target.value})}/></label><button onClick={()=>saveSettings(forms,action)}><Save/> Salvar atualização</button></div>{!isBruno && <p>A validação e aplicação automática continua restrita ao Bruno.</p>}</SettingCard>; }
function AuditPage({data}){ const grouped=useMemo(()=>{ const m={}; for(const a of data.audit) (m[a.action] ||= []).push(a); return m; },[data.audit]); return <div className="stack"><h3><History/> Auditoria do sistema</h3>{Object.entries(grouped).map(([action,rows])=><div className="subpanel" key={action}><h3>{action}</h3><Table rows={rows} render={a=><><td><b>{a.actor}</b><small>{a.entity}</small></td><td>{date(a.created_at)}</td></>}/></div>)}</div>; }
function CentralPro(props){ const showUpdates=props.isBruno || bool(props.settings.SHOW_UPDATES_TO_SINDICO,false); return <Panel title="Sistema e Apps" subtitle="Aplicativos, manuais e atualização do sistema." icon={<ShieldCheck/>}><SubTabs value={props.sub} setValue={props.setSub} tabs={[['apps','Aplicativos'], ...(showUpdates?[['updates','Atualizações']]:[]), ['manuais','Manuais']]} />{props.sub==='updates'&&showUpdates?<Updates {...props}/>:props.sub==='manuais'?<Manuals {...props}/>:<AppsDownload {...props}/>}</Panel>; }
function AppsDownload({settings}){ const apps=[['Portaria','APK_PORTARIA_URL','ENABLE_APP_PORTARIA','#/portaria'],['Síndico','APK_SINDICO_URL','ENABLE_APP_SINDICO','#/dashboard'],['Morador','APK_MORADOR_URL','ENABLE_APP_MORADOR','#/perfil']]; return <div className="appCards downloadApps">{apps.filter(([,u,e])=>bool(settings[e],true)).map(([name,key,,hash])=><article key={name}><Smartphone/><h3>Aplicativo {name}</h3><p>Use como PWA no celular ou baixe o APK quando ele estiver publicado.</p><div className="appActions"><a className="buttonlike" href={window.location.origin+'/'+hash}><AppWindow/> Abrir versão web/app</a>{settings[key]?<a className="buttonlike secondary" href={settings[key]} target="_blank" rel="noreferrer"><Download/> Baixar APK</a>:<button className="buttonlike disabled" type="button" disabled><Download/> APK não publicado</button>}</div></article>)}</div>; }
function Updates({data,forms,setForm,notify,loadAll,isBruno}){ const [progress,setProgress]=useState(0); const [progressText,setProgressText]=useState(''); async function upload(file){ if(!file) return; const fd=new FormData(); fd.append('update_zip',file); fd.append('validation_code',forms.systemUpdate.validation_code||''); try{ setProgress(18); setProgressText('Enviando pacote oficial...'); await new Promise(r=>setTimeout(r,280)); setProgress(52); setProgressText('Validando token, hash e assinatura...'); await request('/api/system-updates/upload',{method:'POST',body:fd,raw:true}); setProgress(100); setProgressText('Atualização validada com segurança.'); notify('Atualização validada.'); await loadAll(); setTimeout(()=>setProgress(0),1800); }catch(e){ setProgress(0); setProgressText(''); notify(e.message,true); } } async function applyUpdate(u){ try{ setProgress(16); setProgressText('Preparando aplicação da atualização...'); await new Promise(r=>setTimeout(r,300)); setProgress(45); setProgressText('Publicando atualização no repositório/deploy...'); const result=await request(`/api/system-updates/${u.id}/apply`,{method:'POST',body:JSON.stringify({validation_code:forms.systemUpdate.validation_code}),headers:{'Content-Type':'application/json'}}); setProgress(80); setProgressText('Atualização enviada. Reiniciando sessão para carregar a nova versão...'); notify(result.message || 'Atualização aplicada. Você será direcionado para a tela de login.'); setTimeout(()=>{ localStorage.removeItem('vr_token'); localStorage.removeItem('vr_user'); window.location.href='/'; }, 4800); setProgress(100); }catch(e){ setProgress(0); setProgressText(''); notify(e.message,true); } } return <div className="updatePanel"><div className="updateDrop premiumUpdate"><UploadCloud/><h3>Enviar atualização oficial</h3><p>Use apenas ZIP oficial com código e token. Depois de aplicar, o sistema volta para a tela de login para carregar a versão nova com segurança.</p><input placeholder="Código/token" value={forms.systemUpdate.validation_code} onChange={e=>setForm('systemUpdate',{validation_code:e.target.value})}/><label className="fileButton"><UploadCloud/> Selecionar ZIP<input type="file" accept=".zip" disabled={!isBruno} onChange={e=>upload(e.target.files?.[0])}/></label>{progress>0&&<div className="progressWrap"><div className="progressTop"><b>{progressText}</b><small>{progress}%</small></div><div className="progressBar"><span style={{width:progress+'%'}}/></div></div>}<div className="noticeBox ok"><b>Observação importante</b><small>Após aplicar uma atualização, entre novamente no sistema. Isso evita carregar telas antigas do navegador durante o deploy.</small></div></div><Table rows={data.systemUpdates} render={u=><><td><b>{u.title||u.version||u.update_code}</b><small>{u.update_code}</small></td><td><Status ok={['validado','aplicado','publicada'].includes(u.status)}>{u.status}</Status></td><td><Code>{u.payload_sha256||'-'}</Code></td><td className="actions">{isBruno&&<button className="confirmAction" onClick={()=>applyUpdate(u)}>Aplicar</button>}</td></>}/></div>; }
function Manuals({data}){ const fallback=[['Manual geral','geral','/manuals/Manual_Geral_Vitoria_Regia_Pro_v9_8.pdf'],['Manual do síndico','síndico','/manuals/Manual_do_Sindico_Vitoria_Regia_Pro_v9_8.pdf'],['Manual da portaria','portaria','/manuals/Manual_da_Portaria_Vitoria_Regia_Pro_v9_8.pdf'],['Manual do morador','morador','/manuals/Manual_do_Morador_Vitoria_Regia_Pro_v9_8.pdf']].map((m,i)=>({id:'static-'+i,title:m[0],audience:m[1],created_at:null,staticUrl:m[2]})); const rows=(data.manuals&&data.manuals.length?data.manuals:fallback); return <Table rows={rows} render={m=><><td><b>{m.title}</b><small>{m.audience}</small></td><td>{m.created_at?date(m.created_at):'Manual padrão'}</td><td><a className="buttonlike" href={m.staticUrl || `${API}/api/manuals/${m.id}/download`} target="_blank" rel="noreferrer"><Download/> Baixar</a></td></>}/>; }
function ChannelChooser({settings,value={},onChange}){ const en=enabledChannels(settings); return <div className="channels"><b>Canais de notificação</b>{Object.entries(en).map(([k,ok]) => ok && <label key={k}><input type="checkbox" checked={value?.[k]!==false} onChange={e=>onChange({...(value||{}),[k]:e.target.checked})}/>{channelNames[k]}</label>)}</div>; }
function SubTabs({value,setValue,tabs}){ return <div className="subTabs">{tabs.map(([k,l])=><button key={k} className={value===k?'active':''} onClick={()=>setValue(k)}>{l}</button>)}</div>; }
function Panel({title,subtitle,icon,children}){ return <section className="panel"><div className="panelHead"><div>{icon}<div><h2>{title}</h2><p>{subtitle}</p></div></div></div>{children}</section>; }
function SettingCard({title,icon,children}){ return <section className="settingsCard"><h3>{icon} {title}</h3>{children}</section>; }
function Metric({icon,label,value,onClick}){ return <button type="button" className="metric" onClick={onClick}><span>{icon}</span><div><b>{value}</b><small>{label}</small></div><ChevronRight className="metricArrow"/></button>; }
function Status({ok,children}){ return <span className={'status '+(ok?'ok':'warn')}>{children}</span>; }
function Code({children}){ return <code className="code">{children}</code>; }
function Table({rows=[],render}){ return <div className="tableWrap"><table><tbody>{rows?.length?rows.map((r,i)=><tr key={r.id||i}>{render(r)}</tr>):<tr><td><small>Nenhum registro encontrado.</small></td></tr>}</tbody></table></div>; }
function ConfirmModal({confirm,onCancel,onConfirm}){ return <div className="modalOverlay"><div className="confirmModal"><h2><CheckCircle2/> {confirm.title}</h2><p>Confira os dados antes de gravar. Essa etapa evita cadastros duplicados ou lançamentos incorretos.</p><div className="confirmList">{Object.entries(confirm.fields||{}).map(([k,v])=><span key={k}>{k}<b>{String(v||'-')}</b></span>)}</div><div className="modalActions"><button onClick={onCancel}>Voltar e corrigir</button><button className="primary" onClick={onConfirm}>Confirmar cadastro</button></div></div></div>; }
function Footer(){ return <footer className="appFooter">Desenvolvido por <b>CrewCheck</b> · Todos os direitos reservados</footer>; }

createRoot(document.getElementById('root')).render(<App/>);
